#include <bits/stdc++.h>
using namespace std;
const int N=1e4+4;
int n,m,a[N],b[N],c[N];
priority_queue<long long> q;
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d%d%d",&a[i],&b[i],&c[i]);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            long long x=1ll*a[i]*j*j+1LL*b[i]*j+c[i];
            if(q.size()<m)
                q.push(x);
            else if(x<q.top())
                q.pop(),q.push(x);
            else
                break;
        }
    stack<long long> s;
    while(q.size())
        s.push(q.top()),q.pop();
    while(s.size()){
        printf("%lld ",s.top());
        s.pop();
    }
    return 0;
}
